class Solution:
    def minPushBox(self, grid) -> int:
        from collections import deque
        m, n = len(grid), len(grid[0])
        def find(ch):
            for i in range(m):
                for j in range(n):
                    if grid[i][j] == ch:
                        return (i, j)
        dirs = [(-1,0),(1,0),(0,-1),(0,1)]
        br, bc = find('B')
        sr, sc = find('S')
        tr, tc = find('T')
        def can_reach(pr, pc, fr, fc, br2, bc2):
            if (pr, pc) == (fr, fc):
                return True
            visited = {(pr, pc)}
            q = deque([(pr, pc)])
            while q:
                r, c = q.popleft()
                for dr, dc in dirs:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and (nr, nc) not in visited and grid[nr][nc] != '#' and (nr, nc) != (br2, bc2):
                        if (nr, nc) == (fr, fc):
                            return True
                        visited.add((nr, nc))
                        q.append((nr, nc))
            return False
        INF = float('inf')
        dist = {}
        dq = deque([(0, br, bc, sr, sc)])
        dist[(br, bc, sr, sc)] = 0
        while dq:
            pushes, r, c, pr, pc = dq.popleft()
            if pushes > dist.get((r, c, pr, pc), INF):
                continue
            if r == tr and c == tc:
                return pushes
            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                need_r, need_c = r - dr, c - dc
                if not (0 <= nr < m and 0 <= nc < n) or grid[nr][nc] == '#':
                    continue
                if not (0 <= need_r < m and 0 <= need_c < n) or grid[need_r][need_c] == '#':
                    continue
                if can_reach(pr, pc, need_r, need_c, r, c):
                    state = (nr, nc, r, c)
                    new_cost = pushes + 1
                    if new_cost < dist.get(state, INF):
                        dist[state] = new_cost
                        dq.append((new_cost, nr, nc, r, c))
        return -1

