var minPushBox = function(grid) {
    const m = grid.length, n = grid[0].length;
    const dirs = [[-1,0],[1,0],[0,-1],[0,1]];
    let br, bc, sr, sc, tr, tc;
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) {
        if (grid[i][j] === 'B') { br = i; bc = j; }
        else if (grid[i][j] === 'S') { sr = i; sc = j; }
        else if (grid[i][j] === 'T') { tr = i; tc = j; }
    }
    function canReach(pr, pc, fr, fc, bor, boc) {
        if (pr === fr && pc === fc) return true;
        const visited = new Set();
        const key = (r, c) => r * n + c;
        visited.add(key(pr, pc));
        const queue = [[pr, pc]];
        let qi = 0;
        while (qi < queue.length) {
            const [r, c] = queue[qi++];
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr < 0 || nr >= m || nc < 0 || nc >= n) continue;
                if (grid[nr][nc] === '#') continue;
                if (nr === bor && nc === boc) continue;
                const k = key(nr, nc);
                if (visited.has(k)) continue;
                if (nr === fr && nc === fc) return true;
                visited.add(k);
                queue.push([nr, nc]);
            }
        }
        return false;
    }
    const INF = Infinity;
    const dist = new Map();
    const stateKey = (r, c, pr, pc) => ((r * n + c) * m * n) + (pr * n + pc);
    const heap = [[0, br, bc, sr, sc]];
    while (heap.length) {
        heap.sort((a, b) => a[0] - b[0]);
        const [pushes, r, c, pr, pc] = heap.shift();
        const sk = stateKey(r, c, pr, pc);
        if ((dist.get(sk) ?? INF) <= pushes) continue;
        dist.set(sk, pushes);
        if (r === tr && c === tc) return pushes;
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            const needR = r - dr, needC = c - dc;
            if (nr < 0 || nr >= m || nc < 0 || nc >= n || grid[nr][nc] === '#') continue;
            if (needR < 0 || needR >= m || needC < 0 || needC >= n || grid[needR][needC] === '#') continue;
            if (!canReach(pr, pc, needR, needC, r, c)) continue;
            const nsk = stateKey(nr, nc, r, c);
            if (pushes + 1 < (dist.get(nsk) ?? INF)) {
                heap.push([pushes + 1, nr, nc, r, c]);
            }
        }
    }
    return -1;
};
